mapper.select:
SELECT COUNT(*) FROM MB_RESERVATION R
JOIN MB_SERVICE_ITEM EXISTING_SERVICE ON EXISTING_SERVICE.ID = R.SERVICE_ID
JOIN MB_SERVICE_ITEM NEW_SERVICE ON NEW_SERVICE.ID = #{serviceId}
WHERE R.STATUS IN ('REQUESTED', 'CONFIRMED') AND R.ID != #{reservationId}
  AND R.RESERVATION_DATE_TIME  <  #{reservationDateTime} + NUMTODSINTERVAL(NEW_SERVICE.DURATION_MINUTES, 'MINUTE')
  AND R.RESERVATION_DATE_TIME + NUMTODSINTERVAL(EXISTING_SERVICE.DURATION_MINUTES, 'MINUTE')  >  #{reservationDateTime}

SELECT COUNT(*)
FROM MB_HOLIDAY
WHERE HOLIDAY_DATE = #{reservationDate}
